import { readFile, writeFile } from "node:fs/promises";
import { createWorkspace } from "@tigrisdata/agent-kit";
import { put } from "@tigrisdata/storage";

async function main(): Promise<void> {
  const rawTrialId = (await readFile("/logs/artifacts/trial_id", "utf8")).trim();
  if (!rawTrialId) {
    console.error("trial_id is empty");
    process.exit(1);
  }

  // S3 bucket names: lowercase letters, numbers, dots and hyphens only.
  const normalizedTrialId = rawTrialId
    .toLowerCase()
    .replace(/[^a-z0-9.-]/g, "-");
  const workspaceName = `harbor-ws-${normalizedTrialId}`;

  const wsResult = await createWorkspace(workspaceName, {
    ttl: { days: 1 },
    credentials: { role: "Editor" },
  });

  if (wsResult.error) {
    console.error("createWorkspace failed:", wsResult.error);
    process.exit(1);
  }

  const workspace = wsResult.data;
  if (!workspace || !workspace.credentials) {
    console.error("createWorkspace did not return scoped credentials");
    process.exit(1);
  }

  const { bucket } = workspace;
  const { accessKeyId, secretAccessKey } = workspace.credentials;

  const body = `{"status":"ok","run":"${rawTrialId}"}`;

  const putResult = await put("state.json", body, {
    contentType: "application/json",
    allowOverwrite: true,
    config: {
      bucket,
      accessKeyId,
      secretAccessKey,
    },
  });

  if (putResult.error) {
    console.error("put failed:", putResult.error);
    process.exit(1);
  }

  await writeFile("/home/user/tigris-task/output.log", accessKeyId);
  console.log(accessKeyId);
}

main().catch((err) => {
  console.error("Unexpected error:", err);
  process.exit(1);
});
